{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 This is about the library, not the plugin itself as it is given only as an example of using most of the library functions. Comments welcome!\par}
{\pard \ql \f0 \sa180 \li0 \fi0 My goals were:\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Automatic resizing of the graphic components\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Automatic memory management\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Written in JSFX exclusively so it's easy to understand, edit and improve Main graphic functions included:\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Linear and non-linear range management\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab GUI for texts and numbers, panels, pictures, knobs, sliders, switches and meters.\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Sliders, switches and knobs have a default style or can be whatever picture you want. Audio functions included:\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Mono and Stereo EQ.\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Enveloppe follower.\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Clipper\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Mono and Stereo Delay (with clipping @+12 dB)\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Conversion utilities (linear vs DB, Frequency vs Omega, Range vs Percent)\sa180\par}
}

